
class Job {final String apiVersion; final String kind; final ObjectMeta metadata; final JobSpec spec; final JobStatus? status; Job({this.apiVersion = 'batch/v1', this.kind = 'Job', required this.metadata, required this.spec, this.status}); factory Job.fromJson(Map<String, dynamic> json) {return Job(apiVersion: json['apiVersion'] ?? 'batch/v1', kind: json['kind'] ?? 'Job', metadata: ObjectMeta.fromJson(json['metadata']), spec: JobSpec.fromJson(json['spec']), status: json['status'] != null ? JobStatus.fromJson(json['status']) : null);} Map<String, dynamic> toJson() {return {'apiVersion' : apiVersion, 'kind' : kind, 'metadata' : metadata.toJson(), 'spec' : spec.toJson(), if (status != null) 'status' : status!.toJson()};}}
